const mdnsServiceTag = "groove-go.local"

// discoveryNotifee receives mDNS peer-found events and connects to them.
type discoveryNotifee struct {
	h host.Host
}

func (n *discoveryNotifee) HandlePeerFound(pi peer.AddrInfo) {
	fmt.Printf("[mdns] found peer: %s — connecting...\n", pi.ID)
	if err := n.h.Connect(n.h.Network().(*dummyNet).ctx, pi); err != nil {
		fmt.Printf("[mdns] connect error: %s\n", err)
	}
}

// StartMDNS starts a local mDNS discovery service on the given host.
// Peers on the same LAN segment will be discovered and connected automatically.
func StartMDNS(h host.Host) (mdns.Service, error) {
	svc := mdns.NewMdnsService(h, mdnsServiceTag, &notifee{h: h})
	if err := svc.Start(); err != nil {
		return nil, fmt.Errorf("mdns start: %w", err)
	}
	fmt.Printf("[mdns] service started (tag=%s)\n", mdnsServiceTag)
	return svc, nil
}

// notifee satisfies mdns.Notifee and connects to discovered peers.
type notifee struct {
	h host.Host
}

func (n *notifee) HandlePeerFound(pi peer.AddrInfo) {
	if pi.ID == n.h.ID() {
		return // skip self
	}
	fmt.Printf("[mdns] found peer: %s\n", pi.ID)
	if err := n.h.Connect(n.h.Network().Peers()[0:0:0], pi); err != nil {
		fmt.Printf("[mdns] connect failed: %s\n", err)
	}
}

